"use client";

import { Button } from "@/components/ui/button";
import {
	Popover,
	PopoverContent,
	PopoverDescription,
	PopoverHeader,
	PopoverTitle,
	PopoverTrigger,
} from "@/components/ui/popover";

export default function PopoverWithArrow() {
	return (
		<Popover>
			<PopoverTrigger render={<Button variant="tertiary" className="w-fit" />}>
				Open Popover
			</PopoverTrigger>
			<PopoverContent withArrow>
				<PopoverHeader>
					<PopoverTitle>With Arrow</PopoverTitle>
					<PopoverDescription>
						This popover has an arrow at its top
					</PopoverDescription>
				</PopoverHeader>
			</PopoverContent>
		</Popover>
	);
}
